      function CF_PROTOCOL_CASEFormula return Char is
V_STRING VARCHAR2(100);
V_AWARD_FLAG VARCHAR2(1);

Cursor cur_award_prompt Is
 SELECT A.AWARD_TYPE_FLAG
FROM PEN_DECISION_INSTANCE A										 
WHERE A.DEC_INCR_SEQ_NO =:P_DEC_INCR_SEC_NO
AND A.DT_DEC_UNIT_CODE=:P_DT_DEC_UNIT_CODE
AND A.DT_DECISION_YEAR=:P_DT_DECISION_YEAR
AND A.DT_DOCUMENT_TYPE_DEC_CODE='1';

begin
	  OPEN cur_award_prompt;
   FETCH cur_award_prompt 
    INTO V_AWARD_FLAG;
   CLOSE cur_award_prompt;
 
 IF :PROTOCOL_NO IS NOT NULL THEN 
 	 IF V_AWARD_FLAG='8' THEN
 	 	IF :CP_DOC_TROP ='006' THEN
 	 	 V_STRING := 'με αριθμό Πρωτοκόλλου '|| :PEN_APPLICATION_INSTANCES_PROT || ' αίτηση περί τροποποίησης ';
 	 	ELSE
 	 	 V_STRING := 'με αριθμό Πρωτοκόλλου '|| :PEN_APPLICATION_INSTANCES_PROT || ' αίτηση περί αναθεώρησης ';
 	 	END IF;	
 	 ELSE
 	 	V_STRING := 'με αριθμό Πρωτοκόλλου '|| :PEN_APPLICATION_INSTANCES_PROT || ' αίτηση περί ';
 	 END IF;	
 ELSE 
     V_STRING := 'οίκοθεν την περίπτωση περί ';
  END IF;    
  return (V_STRING);
end;

      function CF_EMPLOYMENTFormula return nUMBER is
  V_BOOL BOOLEAN;
  v_COND NUMBER;
 	V_WORKING_INS_REDUCTION	 NUMBER;
  V_WORK_INS_CHILD_INCR		 NUMBER;
 	V_WORK_INS_SECTOR				 VARCHAR2(1);
 	
begin

  v_BOOL := Find_SPECIAL_FACT_SUBTYPE(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
			 0,:p_form_id,
			 '00001',
			 '00019',--ΕΡΓΑΣΙΑ (ΕΞΗΡΤΗΜΕΝΗ - ΔΗΜ. ΤΟΜΕΑ)
			 '00033');--ΣΥΝΕΧΙΣΗ ΕΡΓΑΣΙΑΣ
  
  SELECT WORKING_INS_REDUCTION,
  			 WORK_INS_CHILD_INCR,
 				 WORK_INS_SECTOR
 	INTO V_WORKING_INS_REDUCTION,
  		 V_WORK_INS_CHILD_INCR,
 			 V_WORK_INS_SECTOR
  FROM PEN_ACCOUNT
  WHERE ACCOUNT_NO =  :P_ACC_ACCOUNT_NO;
  
  IF V_BOOL =TRUE AND NVL(V_WORKING_INS_REDUCTION,0) != 0 THEN 
  	 V_COND :=1;
  ELSIF V_BOOL =TRUE THEN
  	 V_COND :=2;
  ELSE
  	 V_COND :=3;
  END IF;	 
  
  :CP_1:=V_WORK_INS_SECTOR;
  
  RETURN V_COND;

end;

