      function CF_PRODUCTFormula return Char is

V_PRODUCT_CODE PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_CODE%TYPE;

begin

  SELECT A.PRODUCT_CODE
  INTO V_PRODUCT_CODE
  FROM PEN_PRODUCT_PER_INSTITUTIONS A
  WHERE A.PRODUCT_PER_INSTITUTION_CODE = :P_PRODINST;
  
  RETURN V_PRODUCT_CODE;

end;

      function CF_AGE_LESS_THAN55Formula return NUMBER is

V_NUMBER NUMBER;
BEGIN

	SELECT 	TRUNC(MONTHS_BETWEEN(:P_FACTITIOUS_DATE, DATE_OF_BIRTH)/12)
  INTO V_NUMBER
	FROM		REG_INSURED
	WHERE		REG_INSURED.INSURED_ID = :P_INSURED_ID ;

  IF V_NUMBER<55 THEN 
   RETURN 1;
  ELSE 
  	RETURN 0;
  END IF;
END;

      function CF_SEX_DESCRFormula return Char is

V_SEX VARCHAR2(1);

BEGIN

  SELECT A.SEX
  INTO V_SEX
  FROM REG_INSURED A
  WHERE A.INSURED_ID = :P_INSURED_ID;

  IF V_SEX = 'Α' THEN 
   RETURN 'ΤΟΥ';
  ELSE 
  	RETURN 'ΤΗΣ';
  END IF;
END;

function CF_ANNOUNCEMENTFormula return Char is
V_BRANCH_CODE VARCHAR2(20); V_BRANCH_NAME VARCHAR2(2000);
cursor c1 is SELECT PEN_DEC_FACT_TYPES_INSTANCE.VALUE, DECODE(A.BRANCH_CODE, '09930', 'ΤΜΗΜΑ ΔΙΕΝΕΡΓΕΙΑΣ ΜΕΤΑΒΟΛΩΝ ', A.BRANCH_NAME) BRANCH_NAME FROM PEN_DEC_FACT_TYPES_INSTANCE, COM_ORG_BRANCHES A WHERE PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_INCR_SEQ_NO_SR = :P_DEC_INCR_SEC_NO_SR ---I_DEC_INCR_SEQ_NO1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE ---I_DEC_UNIT1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR ---I_DEC_YEAR1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DOCUMENT_TYPE_DEC_COCE_SR = '00001' ---I_DEC_DOC_TYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.TITLE_CODE = '00172' ---S_SPECIAL_FACT_TYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.DEC_FACT_TYPE_CODE = '00247' ---S_SPECIAL_FACT_SUBTYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.INS_INSURED_ID = :P_Insured_Id ---I_INSURED_ID1 AND PEN_DEC_FACT_TYPES_INSTANCE.STATUS = '1' AND PEN_DEC_FACT_TYPES_INSTANCE.VALUE = A.BRANCH_CODE UNION SELECT PEN_DEC_FACT_TYPES_INSTANCE.VALUE, DECODE(A.BRANCH_CODE, '09930', 'ΤΜΗΜΑ ΔΙΕΝΕΡΓΕΙΑΣ ΜΕΤΑΒΟΛΩΝ ', A.BRANCH_NAME) BRANCH_NAME FROM PEN_DEC_FACT_TYPES_INSTANCE, COM_ORG_BRANCHES A WHERE PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_INCR_SEQ_NO_SR = :P_DEC_INCR_SEC_NO_SR ---I_DEC_INCR_SEQ_NO1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE ---I_DEC_UNIT1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR ---I_DEC_YEAR1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DOCUMENT_TYPE_DEC_COCE_SR = '00001' ---I_DEC_DOC_TYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.TITLE_CODE = '00069' ---S_SPECIAL_FACT_TYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.DEC_FACT_TYPE_CODE = '00247' ---S_SPECIAL_FACT_SUBTYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.INS_INSURED_ID = :P_Insured_Id ---I_INSURED_ID1 AND PEN_DEC_FACT_TYPES_INSTANCE.STATUS = '1' AND PEN_DEC_FACT_TYPES_INSTANCE.VALUE = A.BRANCH_CODE UNION SELECT PEN_DEC_FACT_TYPES_INSTANCE.VALUE, DECODE(A.BRANCH_CODE, '09930', 'ΤΜΗΜΑ ΔΙΕΝΕΡΓΕΙΑΣ ΜΕΤΑΒΟΛΩΝ ', A.BRANCH_NAME) BRANCH_NAME FROM PEN_DEC_FACT_TYPES_INSTANCE, COM_ORG_BRANCHES A WHERE PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_INCR_SEQ_NO_SR = :P_DEC_INCR_SEC_NO_SR ---I_DEC_INCR_SEQ_NO1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE ---I_DEC_UNIT1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR ---I_DEC_YEAR1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DOCUMENT_TYPE_DEC_COCE_SR = '00001' ---I_DEC_DOC_TYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.TITLE_CODE = '01069' ---S_SPECIAL_FACT_TYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.DEC_FACT_TYPE_CODE = '00247' ---S_SPECIAL_FACT_SUBTYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.INS_INSURED_ID = :P_Insured_Id ---I_INSURED_ID1 AND PEN_DEC_FACT_TYPES_INSTANCE.STATUS = '1' AND PEN_DEC_FACT_TYPES_INSTANCE.VALUE = A.BRANCH_CODE UNION SELECT PEN_DEC_FACT_TYPES_INSTANCE.VALUE, DECODE(A.BRANCH_CODE, '09930', 'ΤΜΗΜΑ ΔΙΕΝΕΡΓΕΙΑΣ ΜΕΤΑΒΟΛΩΝ ', A.BRANCH_NAME) BRANCH_NAME ---EE/DS FROM PEN_DEC_FACT_TYPES_INSTANCE, COM_ORG_BRANCHES A WHERE PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_INCR_SEQ_NO_SR = :P_DEC_INCR_SEC_NO_SR ---I_DEC_INCR_SEQ_NO1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE ---I_DEC_UNIT1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR ---I_DEC_YEAR1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DOCUMENT_TYPE_DEC_COCE_SR = '00001' ---I_DEC_DOC_TYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.TITLE_CODE = '99111' ---S_SPECIAL_FACT_TYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.DEC_FACT_TYPE_CODE = '99247' ---S_SPECIAL_FACT_SUBTYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.INS_INSURED_ID = :P_Insured_Id ---I_INSURED_ID1 AND PEN_DEC_FACT_TYPES_INSTANCE.STATUS = '1' AND PEN_DEC_FACT_TYPES_INSTANCE.VALUE = A.BRANCH_CODE ORDER BY 1;
BEGIN
--IF :p_e_yyyyaa IS NOT NULL THEN -- V_BRANCH_NAME := 'ΓΔ Οικονομικών, Διεύθυνση Εκκαθάρισης και Πληρωμής Συντάξεων, Τμήμα Εκκαθάρισης και Πληρωμής Συντάξεων ΕΕ & ΔΣΚΑ'; --ELSE /* V_BRANCH_CODE := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1', 0,:p_form_id,'00001','00172','00247'); IF V_BRANCH_CODE IS NULL THEN V_BRANCH_CODE := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1', 0,:p_form_id,'00001','00069','00247'); END IF;
IF V_BRANCH_CODE IS NULL THEN V_BRANCH_CODE := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1', 0,0,'00001','01069','00247'); END IF; IF V_BRANCH_CODE IS NOT NULL and V_BRANCH_CODE not in ('09930') THEN SELECT A.BRANCH_NAME INTO V_BRANCH_NAME FROM COM_ORG_BRANCHES A WHERE A.BRANCH_CODE = V_BRANCH_CODE; ELSIF V_BRANCH_CODE IS NOT NULL and V_BRANCH_CODE in ('09930') THEN V_BRANCH_NAME:= 'ΤΜΗΜΑ ΔΙΕΝΕΡΓΕΙΑΣ ΜΕΤΑΒΟΛΩΝ '; ELSE V_BRANCH_NAME:= ' '; END IF;*/
OPEN C1; FETCH C1 INTO V_BRANCH_CODE, V_BRANCH_NAME ; CLOSE C1; --END IF;
RETURN NVL(V_BRANCH_NAME, ' '); EXCEPTION WHEN OTHERS THEN RETURN NULL; END;

      function CF_PRESUMED_WAGEFormula return Number is

v_amount number;

CURSOR cur_presumed is 
SELECT A.PRESUMED_WAGES
FROM COM_CURRENT_PRESUMED_WAGES A
WHERE A.PREWAG_INSURANCE_CLASS = :INSURANCE_CLASS
AND A.FROM_DAILY_WAGES <= ROUND(:NOTICE_TOTAL_SALARY/:NOTICE_TOTAL_DAYS,2)
AND (A.TO_DAILY_WAGES >= ROUND(:NOTICE_TOTAL_SALARY/:NOTICE_TOTAL_DAYS,2)
     OR :INSURANCE_CLASS = 28)
AND A.EFFECTIVENESS_START_DATE <= TO_DATE('31'||'12'||:PERIOD_YEAR_TO,'DD/MM/RRRR') 
ORDER BY A.EFFECTIVENESS_START_DATE DESC;

begin
--  insert into error_debug values ('PW',':INSURANCE_CLASS',:INSURANCE_CLASS);
--  insert into error_debug values ('PW',':NOTICE_TOTAL_SALARY',:NOTICE_TOTAL_SALARY);
--  insert into error_debug values ('PW',':NOTICE_TOTAL_DAYS',:NOTICE_TOTAL_DAYS);
--  insert into error_debug values ('PW',':PERIOD_YEAR_TO',:PERIOD_YEAR_TO);
--  commit;
  if :PERIOD_YEAR_TO is not null then
  if nvl(:NOTICE_TOTAL_DAYS,0)!= 0 then 
	  open cur_presumed;
	  fetch cur_presumed
	  into v_amount;
	  close cur_presumed;
	  
--  insert into error_debug values ('PW',':v_amount',v_amount);
--  commit;
  
  else 
  	v_amount:=null;
  end if;
  end if;
  return v_amount;
end;

