pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR =  :p_dt_dec_unit_code AND
pen_dec_fact_types_instance.dec_fact_type_code = '00588';
  

begin
	to_return :='';
	v_end_date:=null;
