      function CF_34Formula return Char is
v_date_char varchar2(10);

v_date_672 varchar2(10);
v_date_673 varchar2(10);

-- CHANGES CHRYS 11/2/2020
CURSOR	CUR_BASIKH IS
SELECT	NVL(AMOUNT,0)
FROM		PEN_QT_PER_BE_CC_PER_ACCOUNT
WHERE 	ACC_ACCOUNT_NO = :P_ACC_ACCOUNT_NO
AND     CP_CALCULATION_PARAMETER_CODE = 'OBBAM';

V_BASIKH_SYNTAKSI		NUMBER;

CURSOR	CUR_KYRIA IS
SELECT	NVL(AMOUNT,0)
FROM		PEN_QT_PER_BE_CC_PER_ACCOUNT
WHERE 	ACC_ACCOUNT_NO = :P_ACC_ACCOUNT_NO
AND     CP_CALCULATION_PARAMETER_CODE = 'OBKYR';

V_KYRIA_SYNTAKSI		NUMBER;

begin
  
  OPEN 	CUR_BASIKH;
  FETCH	CUR_BASIKH
  INTO	V_BASIKH_SYNTAKSI;
  V_DATE_672 := V_BASIKH_SYNTAKSI;
  
  IF CUR_BASIKH%NOTFOUND THEN
  	CLOSE	CUR_BASIKH;
  	v_date_672 := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,
                                             :P_DT_DECISION_YEAR,
                                             :P_DT_DEC_UNIT_CODE,
                                             :P_DEC_INCR_SEC_NO_SR, 
                                             '1',
                                             0,
                                             :p_form_id,
                                             '00001',
                                             '00636',
                                             '00672');
  

  ELSE
  	CLOSE	CUR_BASIKH;
  END IF;
  
  OPEN 	CUR_KYRIA;
  FETCH	CUR_KYRIA
  INTO	V_KYRIA_SYNTAKSI;
  V_DATE_673 := V_KYRIA_SYNTAKSI;
  
  IF CUR_KYRIA%NOTFOUND THEN
  	CLOSE	CUR_KYRIA;
  	v_date_673 := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,
                                             :P_DT_DECISION_YEAR,
                                             :P_DT_DEC_UNIT_CODE,
                                             :P_DEC_INCR_SEC_NO_SR, 
                                             '1',
                                             0,
                                             :p_form_id,
                                             '00001',
                                             '00636',
                                             '00673');
  
  
  ELSE
  	CLOSE	CUR_KYRIA;
  END IF;
  
  v_date_char := NVL(v_date_672,0)+NVL(v_date_673,0);
  
  IF v_date_char = 0 THEN 
  
  v_date_char := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,
                                             :P_DT_DECISION_YEAR,
                                             :P_DT_DEC_UNIT_CODE,
                                             :P_DEC_INCR_SEC_NO_SR, 
                                             '1',
                                             0,
                                             :p_form_id,
                                             '00001',
                                             '00634',
                                             '00634');
  
  
  END IF;
return v_date_char;





end;

