function CF_TOY_THSFormula return Char is
l_toy_ths varchar2(100); begin SELECT 'του ' TOY_THS INTO l_toy_ths FROM REG_INSURED a WHERE a.INSURED_ID = :P_INSURED_ID ;
SELECT DECODE(REG_INSURED.SEX,'Α','του ασφαλισμένου ','Θ','της ασφαλισμένης') INTO l_toy_ths FROM REG_INSURED, PEN_APPLICATION_INSTANCES, COM_ORG_BRANCHES, PEN_QC_PER_PRODINST, PEN_PRODUCT_PER_INSTITUTIONS, PEN_PRODUCTS, COM_PENSION_IKA_INSTITUTION WHERE PEN_APPLICATION_INSTANCES.APPLICATION_INCR_SEQ_NO=:P_APPL_INCR_SEQ_NO AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_UNIT_CODE=:P_APPL_UNIT_CODE AND PEN_APPLICATION_INSTANCES.PDTA_DOCUMENT_TYPE_APPL_CODE='00001' AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_YEAR=:P_APPL_YEAR AND PEN_APPLICATION_INSTANCES.INSURED_ID=:P_INSURED_ID AND REG_INSURED.INSURED_ID=PEN_APPLICATION_INSTANCES.INSURED_ID AND PEN_QC_PER_PRODINST.QC_PER_PRODINST_CODE=:P_QC_PER_PRODINST AND PEN_QC_PER_PRODINST.PRODUCT_PER_INSTITUTION_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_PER_INSTITUTION_CODE AND COM_PENSION_IKA_INSTITUTION.PENSION_IKA_INST_CODE=PEN_PRODUCT_PER_INSTITUTIONS.INSTITUTION_CODE AND PEN_PRODUCTS.PRODUCT_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_CODE AND COM_ORG_BRANCHES.BRANCH_CODE=:P_DT_DEC_UNIT_CODE;
:CP_TOY_THS := l_toy_ths; return (:CP_TOY_THS); EXCEPTION WHEN OTHERS THEN RETURN NULL; end;

      function CF_ALLES_SYNTAKSEISFormula return Char is
  results             Web_auto_pen_recalc.tab_results;
  p_check_number      Number;
  p_check_description Varchar2(2000);
  p_errno             Number;
  p_errtxt            Varchar2(2000);
  p_date              Date         := :P_ACC_START_DATE; --trunc(sysdate);
  p_amka_id           Varchar2(20) := :AMKA_ID;
  p_taxation_id       Varchar2(20) := :TAXATION_ID; 
  eseps_description   Varchar2(200);
  am_in_institution   Varchar2(50); 
  Product_Description Varchar2(200); 
  j                   Number := 0;
  l_string					  Varchar2(2000) := '3.   ';
begin
  -- Call the procedure
  workflow.web_auto_pen_recalc.web_auto_pen_recalc_info(p_date              => p_date,
                                                        p_amka_id           => p_amka_id,
                                                        p_taxation_id       => p_taxation_id,
                                                        results             => results,
                                                        p_check_number      => p_check_number,
                                                        p_check_description => p_check_description,
                                                        p_errno             => p_errno,
                                                        p_errtxt            => p_errtxt);

  
  j := 1; 
  for j in 1..results.count loop
    eseps_description   := results(j).eseps_description;
    am_in_institution   := results(j).am_in_institution;
    Product_Description := results(j).Product_Description; 
    --dbms_output.put_line(' eseps_description  :' ||eseps_description); 
    --dbms_output.put_line(' am_in_institution   :' ||am_in_institution); 
    --dbms_output.put_line(' Product_Description :' ||Product_Description); 
    if l_string	= '3.   ' then 
      l_string := l_string||'Φορέας : '||eseps_description||chr(10)||
                          '      ΑΜΚΑ : '||:AMKA_ID||' -A.M. Φορέα : '|| am_in_institution ||' -Kατηγορία Σύνταξης : '||Product_Description||chr(10);
    else 
    	l_string := l_string||'      Φορέας : '||eseps_description||chr(10)||
                            '      ΑΜΚΑ : '||:AMKA_ID||' -A.M. Φορέα : '|| am_in_institution ||' -Kατηγορία Σύνταξης : '||Product_Description||chr(10);
    end if;
  end loop;
  
  return(l_string);
  exception when others then return null;
end;

      function AfterPForm return boolean is
cursor c1 is
SELECT --decode(COM_ORG_BRANCHES.BRANCH_CODE,'09930','ΓΕΝΙΚΗ ΔΙΕΥΘΥΝΣΗ ΣΥΝΤΑΞΕΩΝ ΔΗΜΟΣΙΟΥ',COM_ORG_BRANCHES.BRANCH_NAME)
       COM_ORG_BRANCHES.BRANCH_NAME,  PEN_PRODUCTS.PRODUCT_CODE
  FROM REG_INSURED, 
       PEN_APPLICATION_INSTANCES, 
	     COM_ORG_BRANCHES, 
	     PEN_QC_PER_PRODINST, 
	     PEN_PRODUCT_PER_INSTITUTIONS,
	     PEN_PRODUCTS,
	     COM_PENSION_IKA_INSTITUTION
 WHERE PEN_APPLICATION_INSTANCES.APPLICATION_INCR_SEQ_NO=:P_APPL_INCR_SEQ_NO
   AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_UNIT_CODE=:P_APPL_UNIT_CODE
   AND PEN_APPLICATION_INSTANCES.PDTA_DOCUMENT_TYPE_APPL_CODE='00001'
   AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_YEAR=:P_APPL_YEAR
   AND PEN_APPLICATION_INSTANCES.INSURED_ID=:P_INSURED_ID
   AND REG_INSURED.INSURED_ID=PEN_APPLICATION_INSTANCES.INSURED_ID
   AND PEN_QC_PER_PRODINST.QC_PER_PRODINST_CODE=:P_QC_PER_PRODINST
   AND PEN_QC_PER_PRODINST.PRODUCT_PER_INSTITUTION_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_PER_INSTITUTION_CODE
   AND COM_PENSION_IKA_INSTITUTION.PENSION_IKA_INST_CODE=PEN_PRODUCT_PER_INSTITUTIONS.INSTITUTION_CODE
   AND PEN_PRODUCTS.PRODUCT_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_CODE
   AND COM_ORG_BRANCHES.BRANCH_CODE=:P_DT_DEC_UNIT_CODE;


cursor c2 is
SELECT PEN_DECISION_INSTANCE.E_DEC_YEAR||'/'||PEN_DECISION_INSTANCE.E_DEC_NO||'*'   , PEN_DECISION_INSTANCE.E_DEC_NO   ,
			 qual_pension_right_date,
			 TO_CHAR(payment_end_date	,'DD/MM/YYYY')  payment_end_date,
			 EPIFILAKSI
  FROM pen_decision_instance
 where dt_decision_year = :P_DT_DECISION_YEAR
  and  dec_incr_seq_no  = nvl(:P_DEC_INCR_SEC_NO,:P_DEC_INCR_SEQ_NO)
  and  dt_dec_unit_code = :P_DT_DEC_UNIT_CODE;

cursor c_wrk is 
select a.dec_orgbra_code||' / '||a.dec_year||' / '||a.dec_sid 
from wrk_decisions a
where a.status   = '1'
and   a.pen_unit = :P_DT_DEC_UNIT_CODE
and   a.pen_year = :P_DT_DECISION_YEAR
and   a.pen_no   = :P_DEC_INCR_SEC_NO
;
	
L_DEC_NO       VARCHAR2(100);
L_EPIFILAKSI   VARCHAR2(1);


cursor c_Fast_Track is
select count(1) cnt
from   pen_dec_fact_types_instance a
where  a.di_document_type_dec_coce_sr = '1'  
and    a.status 			                = '1'
and    a.ins_insured_id               = :p_insured_id 
and    a.di_dec_incr_seq_no_sr        = :p_dec_incr_sec_no_sr 
and    a.di_decision_year_sr          = :p_dt_decision_year 
and    a.di_dec_unit_code_sr          = :p_dt_dec_unit_code 
and    a.title_code                   = '04921'   
and    a.dec_fact_type_code           = '04921' 
and    a.value	                       = '4'   --- 4 -fast track / 2 -non fast track    
;


cursor c_anagnoriseis is
select count(1)
  from pen_ops.Pen_Decision_Instance pdin, 
       Wrk_In_Out wiou, 
       Wrk_Application wapp, 
       Web_Wrk_Appl_EFKA wwae,
       Web_Wrk_EFKA_Cont_Work wecw, 
       Pen_Auto_Ins_Hist paih
where pdin.PAI_PDTA_Application_Unit_Code = wiou.Protocol_Orgbra_Code
   and pdin.PAI_PDTA_Application_Year      = wiou.Protocol_Year
   and pdin.PAI_Application_Incr_Seq_No    = wiou.Protocol_No
   and wiou.Ref_Appl_SID                   = wapp.Appl_SID
   and wapp.Appl_Protocol_Orgbra_Code      = wwae.Appl_Protocol_Orgbra_Code
   and wapp.Appl_Protocol_Year             = wwae.Appl_Protocol_Year               
   and wapp.Appl_Protocol_No               = to_char(wwae.Appl_Protocol_No)
   and wecw.Appl_SID                       = wwae.Appl_SID
   and paih.Call_ID                        = wecw.WS_Iah_Call_ID
   and paih.RecType                        = 5
   and pdin.Status                         = '1'
   and pdin.dt_dec_unit_code               = :P_DT_DEC_UNIT_CODE
   and pdin.dt_decision_year               = :P_DT_DECISION_YEAR
   and pdin.dec_incr_seq_no	               = :P_DEC_INCR_SEC_NO
  ;
  
l_anagnoriseis number:=0;

begin
	open c1;
	fetch c1 into :p_branch_name, :P_PRODUCT_CODE;
	close c1;
	
	open c2;
	fetch c2 into :p_e_yyyyaa,L_DEC_NO, :P_QUAL_PENSION_RIGHT_DATE,  :p_end_date, L_EPIFILAKSI ; 
	close c2;
	
	if l_epifilaksi = '1' then
		:p_epifylaxi := 'Επιφυλασσόμεθα για τυχόν αναθεώρηση της παρούσας σε περίπτωση που εκ των υστέρων προκύψει διαφορά ως προς τα ασφαλιστικά στοιχεία.';
		              --  'προαιρετικής ασφάλισης ή και άλλων χρόνων της ασφαλιστικής σας ιστορίας σύμφωνα με την αίτησή σας.'||chr(10)||
		              --  'Σας παρακαλούμε να προσέλθετε στο αρμόδιο Υποκατάστημα κατόπιν ραντεβού για την ολοκλήρωση της διαδικασίας '||
		              --  'μαζί με τα απαραίτητα έγγραφα';
	end if;	
		
	if :p_end_date is null or :p_end_date = '31/12/2222' 
		then :p_end_date := ' και για χρόνο αόριστο.';
	  else :p_end_date := ' έως και '||:p_end_date;
  end if;		
	if L_DEC_NO is not null then 
	   :p_e_yyyyaa :=	'*e-'||:p_e_yyyyaa;
	else
		 :p_e_yyyyaa := null;
	end if;	 
	     
	:P_insured_id_appear := chr(183)||:P_insured_id||chr(183);
	open c_wrk;
	 fetch c_wrk into :P_WRK_DEC_NO;
	close c_wrk;
	
	 PENPRN_PENSION_REDUCTION(:P_ACC_ACCOUNT_NO,
												 	  1,
												 	  :P_PRODINST,
												 	  :P_PAYMENT_START_DATE,
	                   				:p_MONTHS_200); 
	                   				
	open  c_Fast_Track;
	 fetch c_Fast_Track into :P_FAST_TRACK;
	close c_Fast_Track;
	  
	 --- 23/08/2022 ΟΤΑΝ ΕΚΔΙΔΟΝΤΑΙ ΑΥΤΟΜΑΤΟΠΟΙΗΜΕΝΕΣ ΑΠΟΦΑΣΕΙΣ ΜΕ ΑΝΑΓΝΩΡΙΣΕΙΣ ΘΑ ΕΜΦΑΝΙΖΕΤΑΙ ΣΥΓΚΕΚΡΙΜΕΝΟ ΚΕΙΜΕΝΟ ΣΤΟ ΔΙΑΤΑΚΤΙΚΟ -MAIL ΑΠΟ 22/08/2022 PDROUVAS+ΑΒΑΛΙΑΝ+ΑΜΕΤΑΧΑ
  open  c_anagnoriseis;
  fetch c_anagnoriseis into l_anagnoriseis;
  close c_anagnoriseis;
    
  if nvl(l_anagnoriseis,0) > 0
  	then :P_anagnoriseis := 1; 
    else :P_anagnoriseis := 0;
  end if; 	

  if nvl(:P_anagnoriseis,0) > 0 
    then :p_epifylaxi := 'Επιφυλασσόμεθα για την τροποποίηση της παρούσας απόφασης ως προς τον χρόνο ασφάλισης '||chr(10)||
                         ' που θα προκύψει απο την έκδοση αναγνωριστικής απόφασης, καθώς επίσης και για τον τρόπο '||chr(10)||
                         ' αποπληρωμής του νέου ασφαλιστικού χρόνου.';
  end if;
  
  
  --new prompt for debts mail by tm.nom.syntdde@efka.gov.gr 10/7/2024
  debt_check_5078_enabled( :P_DT_DEC_UNIT_CODE, :P_DT_DECISION_YEAR, :P_DEC_INCR_SEC_NO, :p_debts_prompt, :p_tot_debt );
  
  return (TRUE);
  
end;

function CF_DEPENDENCY_TYPEFormula return Char is
CURSOR C1 IS SELECT --PEN_DECISION_INSTANCE_DEATH.Dependency_Type --PEN_DECISION_INSTANCE_DEATH.Dependency_Type_Dec PEN_DEPENDANT_TYPES.dependency_name FROM PEN_DECISION_INSTANCE_DEATH, PEN_APPLICATION_INSTANCES, PEN_DEPENDANT_TYPES WHERE PEN_APPLICATION_INSTANCES.Pdta_Application_Year =PEN_DECISION_INSTANCE_DEATH.Pdta_Application_Year AND PEN_APPLICATION_INSTANCES.Pdta_Application_Unit_Code =PEN_DECISION_INSTANCE_DEATH.Pdta_Application_Unit_Code AND PEN_APPLICATION_INSTANCES.Application_Incr_Seq_No =PEN_DECISION_INSTANCE_DEATH.Application_Incr_Seq_No AND PEN_APPLICATION_INSTANCES.Pdta_Document_Type_Appl_Code=PEN_DECISION_INSTANCE_DEATH.Pdta_Document_Type_Appl_Code AND PEN_DEPENDANT_TYPES.dependency_type =PEN_DECISION_INSTANCE_DEATH.Dependency_Type_Dec AND PEN_APPLICATION_INSTANCES.APPLICATION_INCR_SEQ_NO =:P_APPL_INCR_SEQ_NO AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_UNIT_CODE =:P_APPL_UNIT_CODE AND PEN_APPLICATION_INSTANCES.PDTA_DOCUMENT_TYPE_APPL_CODE='00001' AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_YEAR =:P_APPL_YEAR AND PEN_APPLICATION_INSTANCES.INSURED_ID =:P_INSURED_ID ;
L_DESCR VARCHAR2(200); begin OPEN C1; FETCH C1 INTO L_DESCR; CLOSE C1; RETURN (L_DESCR); end;

