      function CF_FIND_SUM_YY_MM_DDFormula return Number is
lidaysofmonth number:= 25;
begin
  -- Call the procedure
  com_util_days.convdaysinyearsmontsdays(pisumofdays   => :CS_SUM_DAYS,
                                         pidaysofmonth => lidaysofmonth,
                                         poyears       => :CP_SUM_YY,
                                         pomonths      => :CP_SUM_MM,
                                         podays        => :CP_SUM_DD);
  return (:CP_SUM_YY);
  exception when others then return null;
end;

