      function CF_DEBT_DESCR_AUTOFormula return Char is


TO_RETURN VARCHAR2(1000);


CURSOR C2_128 IS
select   DEDUCTION_PENSION_FACTOR, 
         DOSAGE_AMOUNT, 
         TOTAL_DEDUCTION_AMMOUNT,
         STATUS 
from PEN_DEC_INSTANCE_DEBTS a
WHERE  DT_DEC_UNIT_CODE= :p_DT_DEC_UNIT_CODE
   AND DT_DECISION_YEAR= :p_DT_DECISION_YEAR
   AND DEC_INCR_SEQ_NO = :P_DEC_INCR_SEC_NO
   AND a.STATUS        = '1'
   AND a.debt_id	     = '128'
   ;

CURSOR C2_129 IS
select   DEDUCTION_PENSION_FACTOR, 
         DOSAGE_AMOUNT, 
         TOTAL_DEDUCTION_AMMOUNT,
         STATUS 
from PEN_DEC_INSTANCE_DEBTS a
WHERE  DT_DEC_UNIT_CODE= :p_DT_DEC_UNIT_CODE
   AND DT_DECISION_YEAR= :p_DT_DECISION_YEAR
   AND DEC_INCR_SEQ_NO = :P_DEC_INCR_SEC_NO
   AND a.STATUS        = '1'
   AND a.debt_id	     = '129'
   ;   
   
   lDOSAGE_AMOUNT            varchar2(100);
   lTOTAL_DEDUCTION_AMMOUNT  varchar2(100);
   lDEDUCTION_PENSION_FACTOR varchar2(100);
   lSTATUS                   varchar2(100);
begin
	
  	
  --SRW.MESSAGE(100, ':p_debts_prompt -> '||:p_debts_prompt);
  --SRW.MESSAGE(100, ':p_tot_debt -> '||:p_tot_debt);

	IF NVL(:p_debts_prompt,0) >  0  AND NVL(:p_tot_debt,0) >= 20000 
		  THEN
		
	/*	  	OPEN C1;
		  	FETCH C1 INTO V_PRCN_DESCR,V_PRCN;
		  	CLOSE C1;
	 		TO_RETURN := '3. Παρακράτηση '||:DOSAGE_AMOUNT||' ('||V_PRCN||'% της μηνιαίας σύνταξης) της μηνιαίας σύνταξης για οφειλές παρακράτησης συνολικού ποσού '||:TOTAL_DEDUCTION_AMMOUNT||
                 	 ' (ποσό οφειλής που υπερβαίνει τις '||:TOTAL_DEDUCTION_AMMOUNT ||'/'||:DOSAGE_AMOUNT|| ' για τ. '||:P_PENSION_IKA_NAME ||')'||CHR(10)||
               	   '4. Παρακράτηση ποσού '||:DOSAGE_AMOUNT||' της μηνιαίας Σύνταξης για οφειλές παρακράτησης σε δόσεις από συνολικό ποσό '||:TOTAL_DEDUCTION_AMMOUNT||
                   ' ('||:TOTAL_DEDUCTION_AMMOUNT||'/'||:DOSAGE_AMOUNT||' τ. '||:P_PENSION_IKA_NAME  ||').';*/  ---18/9/2024 APO METAXA ALLAGH
    
        OPEN  C2_128;
		  	FETCH C2_128 INTO lDEDUCTION_PENSION_FACTOR, lDOSAGE_AMOUNT, lTOTAL_DEDUCTION_AMMOUNT, lSTATUS;
		  	CLOSE C2_128;          
    
    IF NVL(lSTATUS,'0') = '1' THEN
      TO_RETURN :=     '3. Παρακράτηση ποσοστού 60% της μηνιαίας σύνταξης έως την εξόφληση οφειλής από εισφορές ποσού ' || lTOTAL_DEDUCTION_AMMOUNT ||' ΕΥΡΩ Ν. 5078/23.'||CHR(10);
    END IF;
    
        OPEN  C2_129;
		  	FETCH C2_129 INTO lDEDUCTION_PENSION_FACTOR, lDOSAGE_AMOUNT, lTOTAL_DEDUCTION_AMMOUNT, lSTATUS;
		  	CLOSE C2_129;
		IF NVL(lSTATUS,'0') = '1' THEN  	     
      TO_RETURN :=  TO_RETURN || '4. Παρακράτηση ποσού '||lDOSAGE_AMOUNT||' ΕΥΡΩ της μηνιαίας σύνταξης για οφειλή από εισφορές ποσού '||lTOTAL_DEDUCTION_AMMOUNT||' ΕΥΡΩ (60 μηνιαίες δόσεις) Ν. 5078/23. ';
    END IF;  
	 --SRW.MESSAGE(100, ':TO_RETURN -> '||TO_RETURN);
	END IF;
  
  return TO_RETURN;
  EXCEPTION WHEN OTHERS THEN RETURN NULL;
		
end;

